@dataclass
class ExecContext:
  var_vals: dict[str, int] = field(default_factory=dict)
  input_uops: tuple[UOp, ...] = ()
  do_update_stats: bool = True
  jit: bool = False

def _resolve(b:UOp, inputs:tuple[UOp, ...]) -> UOp:
  if b.op is Ops.BUFFER_VIEW and b.src[0].op is Ops.PARAM: return b.replace(src=(inputs[b.src[0].arg], *b.src[1:]))
  return inputs[b.arg] if b.op is Ops.PARAM else b
def resolve_params(call:UOp, inputs:tuple[UOp, ...]) -> list[UOp]: return [_resolve(b, inputs) for b in call.src[1:] if b.op is not Ops.BIND]

@contextlib.contextmanager
def track_stats(ctx:ExecContext, call:UOp, device:str, display_name:str, estimates:Estimates, bufs:list[Buffer], var_vals:dict[str, int],
                outputs=(0,), inputs=(1,), first_run=False):
  if PROFILE: cpu_events.append(ProfilePointEvent(device, "exec", len(cpu_events), {"metadata": call.arg.metadata, "var_vals": var_vals,
                                                  "bufs": [b.trace_num for b in bufs], "name": display_name, "outputs": outputs, "inputs": inputs}))
  timing: list[float|None] = [None]
  if DEBUG >= 2: st = time.perf_counter()
  yield timing
  if not ctx.do_update_stats: return
  if DEBUG >= 2 and timing[0] is None:
    Device[device].synchronize()
    timing[0] = time.perf_counter() - st
  update_stats(display_name, device, estimates, var_vals, timing[0], len(bufs), jit=ctx.jit, metadata=call.arg.metadata, first_run=first_run)

def unwrap_multi(call:UOp, resolved:list[UOp]) -> Iterator[tuple[list[Buffer], dict[str, int]]]:
  bufs = [b.buffer for b in resolved]
  if not any(isinstance(b, MultiBuffer) for b in bufs): yield cast(list[Buffer], bufs), {}
  else:
    dnum = next((x.expr for x in call.src[0].variables() if x.expr == '_device_num'), None)
    for j, per_dev in enumerate(zip(*[cast(MultiBuffer, b).bufs for b in bufs])): yield list(per_dev), {dnum: j} if dnum else {}

  for call in self.linear.src:
    replace = [(p, b.arg) for p, b in enumerate(b for b in call.src[1:] if b.op is not Ops.BIND) if b.op is Ops.PARAM]
    for dev_idx, (bufs, device_vars) in enumerate(unwrap_multi(call, resolve_params(call, input_uops))):
      self.calls.append((dev_idx, call.src[0], [b.ensure_allocated() for b in bufs], device_vars))
      self.progs.append(get_runner(bufs[0].device, call.src[0]) if call.src[0].op in (Ops.SINK, Ops.PROGRAM) else None)
      self.uop_replace.append(replace)

  self.var_vals_replace:dict[int, list[tuple[int, int]]] = {}
  self.launch_dims_replace:dict[int, tuple[int|None, int|None]] = {}
  self.launch_dims_base:dict[int, tuple[tuple[int, ...], tuple[int, ...]]] = {}

  def is_sym_dim(dim) -> bool: return not all(isinstance(d, (int, float)) for d in dim)

  crs = [(ji, ji.prg) for ji in self.jit_cache if isinstance(ji.prg, CompiledRunner)]
  self.vars = sorted({v.expr for ji,p in crs for v in p.p.vars if v.expr not in ji.fixedvars | p.p.runtimevars})
  self.symbolic_dims = dedup([tuple(d) for _,p in crs if (d:=p.p.local_size) and is_sym_dim(d)] +
                             [tuple(d) for _,p in crs if (d:=p.p.global_size) and is_sym_dim(d)])

  def find_symbolic_dim(dim): return self.symbolic_dims.index(tuple(dim)) if dim is not None and tuple(dim) in self.symbolic_dims else None

  estimates = Estimates()
  for j,ji in enumerate(self.jit_cache):
    assert ji.prg is not None
    estimates += ji.prg.estimates
    if isinstance(ji.prg, CompiledRunner):
      if (replace:=[(i, self.vars.index(v.expr)) for i, v in enumerate(ji.prg.p.vars) if v.expr not in ji.fixedvars | ji.prg.p.runtimevars]):
        self.var_vals_replace[j] = replace

      global_dim_idx, local_dim_idx = find_symbolic_dim(ji.prg.p.global_size), find_symbolic_dim(ji.prg.p.local_size)
      if global_dim_idx is not None or local_dim_idx is not None:
        self.launch_dims_replace[j] = (global_dim_idx, local_dim_idx)
        assert ji.prg.p.local_size is not None
        self.launch_dims_base[j] = (tuple(ji.prg.p.global_size), tuple(ji.prg.p.local_size))

  # used in MultiGraphRunner. tracks (offset, end, dep) ranges per base buffer id to handle suballocated buffers correctly.
  self.w_dependency_map: dict[int, list[tuple[int, int, Any]]] = collections.defaultdict(list)
  self.r_dependency_map: dict[int, list[tuple[int, int, Any]]] = collections.defaultdict(list)

  assert self.jit_cache[0].prg is not None
  super().__init__(colored(f"<batched {len(self.jit_cache)}>", "cyan"), self.jit_cache[0].prg.device.split(":")[0], estimates.simplify())

def updated_vars(self, var_vals: dict[str, int]):
  vals = [var_vals[v] for v in self.vars]
  for j, vidxs in self.var_vals_replace.items():
    for i, v in vidxs: yield j, i, vals[v]

def updated_launch_dims(self, var_vals: dict[str, int]):
  dims = [tuple(sym_infer(s, var_vals) for s in dim) for dim in self.symbolic_dims]
  for j, (gl, lc) in self.launch_dims_replace.items():
    yield j, (dims[gl] if gl is not None else self.launch_dims_base[j][0]), (dims[lc] if lc is not None else self.launch_dims_base[j][1])

  return UOp.empty(self.shard_shape if axis is not None else self.shape, self.dtype if dtype is None else dtype, device, axis)
@property
def device(self) -> str|tuple[str, ...]: return unwrap(self._device)
@recursive_property
def _device(self) -> str|tuple[str, ...]|None:
  if self.op is Ops.DEVICE: return self.arg
  if self.op is Ops.BUFFERIZE: return self.arg.device
  if self.op is Ops.AFTER: return self.src[0]._device
  if self.op is Ops.MSELECT:
    assert isinstance(self.src[0].device, tuple), f"mselect must be on tuple device, getting {self.src[0].device}"
    return self.src[0].device[self.arg]
  if self.op is Ops.MSTACK: return tuple(cast(str, x.device) for x in self.src)
  if self.op in {Ops.COPY, Ops.BUFFER, Ops.ALLREDUCE}: return self.src[1].device
  for x in self.src:
    if x._device is not None: return x._device
  return None
@property
def buf_uop(self) -> UOp:
  if self.op in {Ops.BUFFER, Ops.PARAM}: return self
  if self.op is Ops.MSELECT: return self.src[0].buf_uop.mselect(self.arg)
  if self.op is Ops.MSTACK: return UOp(Ops.MSTACK, self.dtype, src=tuple(x.buf_uop for x in self.src))
  if self.base.op is Ops.AFTER: return self.base.src[0].buf_uop.base
  s = self
  while len(s.src) and s.op not in {Ops.BUFFER, Ops.PARAM, Ops.BUFFERIZE, Ops.MSTACK}: s = s.src[0]
  return s

def contiguous_view_offset(self) -> int|None:
  """If movement ops on a BUFFER collapse to a contiguous range, return `offset` in elements. Otherwise None."""
  from tinygrad.schedule.rangeify import pm_mops
  from tinygrad.uop.symbolic import symbolic
  numel = self.numel()
  out = graph_rewrite(self.flatten().index(UOp.range(numel, 0)), pm_mops+symbolic, name="contiguous_view_offset")
  if out.op is not Ops.INDEX: return None
  if out.src[1].op is Ops.CONST and resolve(numel == 1, False):
    if not isinstance(out.src[1].arg, int): return None  # masked/padded regions produce InvalidType
    return out.src[1].arg
  if out.src[1].op is Ops.RANGE: return 0
  if out.src[1].op is Ops.ADD and out.src[1].src[0].op is Ops.RANGE and out.src[1].src[1].op is Ops.CONST:
    if not isinstance(out.src[1].src[1].arg, int): return None  # masked/padded regions produce InvalidType
    return out.src[1].src[1].arg
  return None

def has_buffer_identity(self):
  """Check if this UOp has a concrete buffer identity in the graph (RESHAPE/MULTI -> BUFFER chain)."""
  if self.op in {Ops.RESHAPE, Ops.MULTI}: return self.src[0].has_buffer_identity()
  if self.op is Ops.GETTUPLE and self.src[0].op is Ops.TUPLE: return self.src[0].src[self.arg].has_buffer_identity()
  return self.op in {Ops.BUFFER, Ops.BUFFER_VIEW, Ops.PARAM}

def _base_buffer_is_realized(self) -> bool:
  """Walk through AFTER chain to find if the underlying buffer is realized (has allocated memory)."""
  u = self.base
  while u.op is Ops.AFTER: u = u.src[0]
  return u.is_realized

@property
def buffer(self) -> Buffer|MultiBuffer:
  if self.op in {Ops.CONTIGUOUS, Ops.RESHAPE, Ops.DETACH, Ops.AFTER}: return self.src[0].buffer
  # this buffer can process disk tensors and simple movement ops
  if self is not self.base:
    buf = self.base.buffer
    assert isinstance(buf, Buffer), "must be a Buffer for movement ops"
    offset = self.contiguous_view_offset()
    if offset is None: raise RuntimeError(f"non-contiguous view is not supported for {buf.device} buffer")
    return buf.view(prod(self.max_shape), self.dtype, offset*self.dtype.itemsize)
  if self.op is Ops.BITCAST:
    buf = self.src[0].buffer
    assert isinstance(buf, Buffer), "must be a Buffer for BITCAST"
